mapper.select:
select distinct u.user_id, u.dept_id, u.user_name, u.nick_name, u.email, u.phone, u.status, u.create_time from sys_user u left join sys_dept d on u.dept_id = d.dept_id left join sys_user_role ur on u.user_id = ur.user_id left join sys_role r on r.role_id = ur.role_id where u.del_flag = '0' and r.role_id = #{roleId}
AND u.user_name like concat('%', #{userName}, '%')
AND u.phone like concat('%', #{phone}, '%')
${params.dataScope}

select u.user_id, u.dept_id, u.nick_name,u.user_type, u.user_name, u.email, u.avatar, u.phone, u.sex, u.status,u.online, u.del_flag, u.login_ip, u.login_date, u.create_id, u.create_time, u.remark,u.source,u.channel, d.dept_name,d.leader from sys_user u left join sys_dept d on u.dept_id = d.dept_id where u.del_flag = '0'
AND u.user_id = #{userId}
AND u.user_type = #{userType}
AND u.user_name like concat('%', #{userName}, '%')
AND u.status = #{status}
AND u.phone like concat('%', #{phone}, '%')
AND date_format(u.create_time,'%y%m%d') >= date_format(#{params.beginTime},'%y%m%d')
AND date_format(u.create_time,'%y%m%d') <= date_format(#{params.endTime},'%y%m%d')
AND (u.dept_id = #{deptId} OR u.dept_id IN ( SELECT t.dept_id FROM sys_dept t WHERE find_in_set(#{deptId}, ancestors) ))
${params.dataScope} ORDER BY u.create_time desc

select t.user_id, u.nick_name, u.avatar,t.visitor_id as visitor_user_id, t.content as last_msg,t.update_time as last_time from chat_user_visitor_talk t LEFT JOIN chat_visitor u ON t.visitor_id = u.user_id WHERE t.user_id = #{userId}
AND u.nick_name like concat('%', #{nickName}, '%')
order by t.update_time desc

SELECT u.user_id,u.user_name,u.default_pwd,uc.id,uc.nick_name,uc.expire_time,uc.create_time,uc.status,c.name,c.short_name,uc.company_id,c.create_id FROM `sys_user` u JOIN `sys_user_company` uc ON u.user_id=uc.user_id JOIN `sys_company` c ON uc.company_id = c.id
AND u.dept_id = #{deptId}
AND u.nick_name like concat('%', #{nickName}, '%')
AND u.user_name like concat('%', #{userName}, '%')
AND uc.status = #{status}
order by uc.create_time desc
